var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"도착할 때까지 트렁크에 처박혀 있으라니, 취급이 왜 이래?","JPN":"着くまでトランクに隠れてろだなんて、あんまりなんじゃないか？","ENG":"You want me to stay in the trunk the whole ride over? Are you serious?","TWN":"竟然要我抵達前先待在後車廂裡，為什麼這樣對我？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L4_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"조금만 참아. 네 몽타주가 이미 블랙 네트워크에 쫙 깔렸어.","JPN":"もう少し我慢しろ。お前のモンタージュがすでにブラックネットワークに広がっている。","ENG":"Just hang in there. Your picture is already plastered all throughout the Dark Network.","TWN":"你忍耐一下，誰叫你的畫像已經在黑色網路上傳開來。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그리고 이 도시는 그라운드 원이다. 현상금이라면 눈에 불을 켤 용병들이 많지.","JPN":"それにこの都市はグラウンド・ワンだ。懸賞金とあれば目の色が変わる傭兵がたくさんいる。","ENG":"Also, this is Ground One. Mercenaries are always on the lookout for some bounty.","TWN":"再者這裡可是G1，有很多傭兵都在覬覦懸賞金好嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"……사례금 챙기는 우리처럼 말이지.","JPN":"……謝礼貰ってる私たちみたいにね。","ENG":"...Just like us.","TWN":"……就像我們會拿報酬一樣嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"대장, 복수를 하기 위해서라면 뭐든지 할 수 있어.","JPN":"隊長、復讐のためなら何だってできる。","ENG":"Captain, I'm ready to do anything for revenge.","TWN":"隊長，為了報仇，我什麼都願意做。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"하지만, 돈이 엮이게 되는 순간부터는…….","JPN":"でも、金が絡んでくる瞬間からは……","ENG":"But, when money gets involved...","TWN":"但牽扯到金錢的瞬間……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"암을 치료할 수 있었다면, 지훈이 놈이 죽으려고 했을까?","JPN":"癌を治療することができたら、ゴトウは死のうと思っただろうか？","ENG":"Do you think Jihoon would have sacrificed himself if he could treat his cancer?","TWN":"要是可以治療癌症的話，你認為智勳那傢伙還會想死嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"지금 그 녀석 얘기가 왜 나와?","JPN":"そこでなんであいつの話が出てくるんだよ。","ENG":"Why are you bringing him up now?","TWN":"現在為何要提到他？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"성냥팔이를 해치운 뒤로 계속 해 왔던 고민이다.","JPN":"マッチ売りとのことがあってからずっと悩んできたことだ。","ENG":"I've been thinking about it ever since we defeated Matchmaker.","TWN":"除掉賣火柴的後，我一直在想這件事。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"내가 그 놈에게 왜 그런 화려한 은퇴식을 치러 줘야 했는지 말이다.","JPN":"なぜ俺はあいつにあんな派手な引退式をしてやるしかなかったのか。","ENG":"You know, why I let him go out with a bang like that.","TWN":"我為何必須要替他辦那麼華麗的退休儀式？"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……분명 그보다 더 나은 결말도 있었을 텐데.","JPN":"……きっとそれよりましな結末もあったはずなのに。","ENG":"...There had to have been a better way.","TWN":"……他明明可以有更好的下場。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"이제 와서 동료애라도 생겼어? 나더러 총알받이 운운할 때는 언제고.","JPN":"今更仲間を惜しむ気持ちが芽生えたってのか？　私を弾除けだって言ったくせに。","ENG":"Did you just develop comradery for your team? You put me through all that human shield crap, too.","TWN":"你現在突然產生同胞愛嗎？之前是誰叫我當砲灰的？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그럼 애초에 우리가 이 짓을 계속 할 필요는 뭐야?! 각자 살 길 찾으라고 할 것이지!","JPN":"そもそもこの仕事を続ける理由は何だよ！？　各自勝手にやらせておけばいいじゃないか！","ENG":"Then what's the point of us continue doing this?! Why not just tell us to find another occupation?","TWN":"那我們為何要持續做這件事？！打從一開始就各自尋找活路就好啦！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_BIG"},{"id":"L22_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"동료애 같은 말 대신 효율이라고 해라.","JPN":"仲間を惜しむ気持ちじゃなく、効率って言え。","ENG":"It's not about comradery, it's about being efficient.","TWN":"這不是同胞愛，是效率。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"도착하기 전까지 무전기는 끄고 있어. 배터리 방전되면 골치 아파진다.","JPN":"着くまで無線機の電源は切っておけよ。バッテリーがなくなると面倒なことになる。","ENG":"Make sure to turn off your comms until we arrive. It's gonna be a hassle if your battery dies later.","TWN":"抵達前先關掉無線電，萬一沒電的話會很傷腦筋的。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"역시 민우 대장, 앞으로는 무뚝뚝한 척 하면서 사실은 대원들에게 끈끈한 정을 느끼는 거네요.","JPN":"さすがマツダ隊長、人前ではぶっきらぼうなふりをしてても、実は隊員たちに深い情を抱いているんですね。","ENG":"Wow, Captain. You always put on this facade of being indifferent, but you seem to really care about your team.","TWN":"真不愧是民宇隊長，之後你面無表情的時候，我都會感受到你對隊員濃烈的愛。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"조용히 있어, 레비아. 운전에 집중해야 하니까.","JPN":"静かにしろ、レヴィア。運転には神経使うんだ。","ENG":"Stop distracting me, Levia. I'm driving.","TWN":"莉維亞，你安靜點，我要專心開車。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"나도 네 장난질을 조용히 넘어가 주지 않았나?","JPN":"俺もお前のいたずらを見ないふりしてやっただろう？","ENG":"Don't I look the other way for your pranks too?","TWN":"我也沒拿你的玩笑大做文章吧？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"에헤. 전 진짜 부축만 해 드렸다니까요.","JPN":"えへっ。私は本当に支えてあげただけですって。","ENG":"Ehet. I really was just lending you a hand.","TWN":"嘿嘿，我真的只有扶你而已啦。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"위협용으로 쏜 총알이 중상을 입혔다. 코앞에 있는 것도 아닌 상대에게.","JPN":"威嚇するために撃った弾丸が重傷を負わせた。すぐ目の前にいたわけでもない相手にだ。","ENG":"My warning shot ended up injuring a person. And a far away one at that.","TWN":"基於威嚇作用發射的子彈卻造成重傷，而且還是在有點距離的情況下。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"나에게 신들린 저격 솜씨 따위 없어. 의심할 만한 건 카운터인 너밖에 없다.","JPN":"俺に神懸かった狙撃の腕なんかない。疑わしいのはカウンターであるお前しかいない。","ENG":"I don't have godlike sniping skills, so the only one to suspect of foul play is you, a Counter.","TWN":"我個人又沒什麼神射手的天份，能夠懷疑的就只有制裁者的你。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"……유리 언니가 잡힐까 봐 그런 거예요.","JPN":"……ユリさんが捕まるかもしれないと思って。","ENG":"...I did it because I thought Yuri was gonna get caught.","TWN":"……我是怕悠麗姊姊被抓到才那麼做的。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"상대를 동요시키려면 짝을 노리는 게 제일이니까요. 일을 복잡하게 만들 의도는 없었어요.","JPN":"相手を動揺させるためには、パートナーを狙うのが一番ですから。事を複雑にするつもりはなかったんです。","ENG":"And the best way to distract the officer was by aiming at her partner. I didn't mean for things to get so complicated.","TWN":"因為要使對方分心，最好的方法就是瞄準她的同伴，我不是故意要讓事情變複雜的。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"강소영, 그 녀석은…….","JPN":"マエカワ・ナツミ、あいつは……","ENG":"Kang Soyoung. She was...","TWN":"姜素英，她是……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"레비아. 내가 네 머리에 총알을 안 박아 넣은 건 널 예쁘게 봐서가 아냐.","JPN":"レヴィア。俺がお前の頭に弾丸を撃ち込まなかった理由は気に入っているからじゃない。","ENG":"Levia. The reason I didn't put a bullet in your head then was not because I think you did a good job.","TWN":"莉維亞，我沒往你腦袋開槍，不是對你特殊待遇。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"이유리를 거기 놔두고 서로 총질이나 할 수 없어서지.","JPN":"カスカベがいるのに撃ち合いなんぞできないだろ。","ENG":"It was because I prioritized saving Yuri first above anything else.","TWN":"只是不能將李悠麗扔在那裡，讓她們彼此殘殺。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"베로니카는 나와 유리 둘이 맡을 계획이다.","JPN":"ベロニカは俺とカスカベで担当するつもりだ。","ENG":"Yuri and I are going to mark Veronica.","TWN":"貝洛妮卡就交給我和悠麗。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"지난번처럼 맨션이 개입할 수 있어. 너는 매복해서 녀석들을 막아라.","JPN":"この前のようにマンションが介入する可能性がある。お前は待ち伏せしてやつらを止めろ。","ENG":"I suspect Mansion is going to intervene like last time. So I want you to hide and ambush them if they appear.","TWN":"曼森很可能會和上次一樣介入，你埋伏起來擋住他們。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"대장…… 화 많이 났어요? 분명히 한 명이 아쉽다고…….","JPN":"隊長……怒ってますか？　確か人手が必要だって……","ENG":"Captain... are you mad at me? Didn't you say you needed all the help you can get...?","TWN":"隊長……你很生氣嗎？你不是說一個都不能少嗎……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그 이상은 말하지 마라, 레비아.","JPN":"それ以上は言うな、レヴィア。","ENG":"That's enough, Levia.","TWN":"話就說到這裡，莉維亞。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"악을 쓰고 몸부림쳐 봤자 아무것도 해결 안 된다는 건 이미 예전에 배웠어.","JPN":"泣き騒いでじたばたしたところで何も解決しないのはとっくにわかってるんだ。","ENG":"I learned a long time ago that screaming and struggling doesn't solve anything.","TWN":"我從以前就學到，耍賴並無法解決任何事情。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그러니 지금은 그저 일이 더 꼬이기 전에 이 빌어먹을 의뢰를 끝내는 게 내 소원이다.","JPN":"だから今はもっとややこしくなる前にこのクソみたいな依頼を終わらせるのが俺の願いだ。","ENG":"So what I want is to finish this job before it gets any more complicated.","TWN":"我現在只有一個想法，就是在情況變得更複雜之前，把那該死的委託解決掉。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"……알았어요, 대장.","JPN":"……わかりました、隊長。","ENG":"...Okay, Captain.","TWN":"……好的，隊長。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"빌어먹을.","JPN":"ちくしょう。","ENG":"Dammit!","TWN":"該死。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_06"}]`);export{e as default};